sp_widget.client_script:
function ($scope, $rootScope, amb, spUtil) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
var c = this;
	c.comments_count = 0;

	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;
	initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				refreshWidget();
			});
		}
	}

	//var onListClick = $scope.$on('$sp.list.click', refreshWidget);
	//var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);
	// determines if there are any comments for this task
	for(var x = 0; x < $scope.data.stream.entries.length; x++){
		if($scope.data.stream.entries[x].element == 'comments'){
			c.comments_count++;
		}
	}

	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		c.data.table = parms.table;
		c.data.sys_id = parms.sys_id;
		refreshWidget();
	});
	$rootScope.$on('$sp.list.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});

	function refreshWidget() {
		$scope.server.update().then(function(){
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			initRecordWatcher(c.data.table, c.data.filter);
		});
	}

}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {

	var gr;
	if(input){
		gr = new GlideRecordSecure(input.table);
		if(!gr.get(input.sys_id)){
			return;
		}
	}	else{
		gr = $sp.getRecord();
	}

	if (gr == null)
		return;

	data.canRead = gr.canRead();
	if (!data.canRead) 
		return;

	data.table = gr.getTableName();
	data.sys_id = gr.getUniqueValue();
	data.stream = $sp.getStream(data.table, data.sys_id);
	data.comments_count=0;
	for(var x = 0; x < data.stream.entries.length; x++){
		if(data.stream.entries[x].element == 'comments'){
			data.comments_count++;
		}
	}	
})($sp, input, data, options, gs);
